import{_ as a,o as t,c as n,ae as s}from"./chunks/framework.DTwQaIIa.js";const m=JSON.parse('{"title":"PlaceholderAPI 占位符","description":"","frontmatter":{},"headers":[],"relativePath":"modules/strengthen/placeholders.md","filePath":"modules/strengthen/placeholders.md"}'),d={name:"modules/strengthen/placeholders.md"};function o(c,e,r,i,l,h){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="placeholderapi-占位符" tabindex="-1">PlaceholderAPI 占位符 <a class="header-anchor" href="#placeholderapi-占位符" aria-label="Permalink to &quot;PlaceholderAPI 占位符&quot;">​</a></h1><p>EmakiStrengthen 提供了一组 <a href="https://www.spigotmc.org/resources/placeholderapi.6245/" target="_blank" rel="noreferrer">PlaceholderAPI</a> 外部占位符，可在计分板、HUD 等任何支持 PAPI 的场景中使用。</p><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>服务器需安装 PlaceholderAPI 插件。EmakiStrengthen 会在启动时自动检测并注册，无需手动配置。</p></div><h2 id="标识符" tabindex="-1">标识符 <a class="header-anchor" href="#标识符" aria-label="Permalink to &quot;标识符&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>emakistrengthen</span></span></code></pre></div><h2 id="主手物品强化状态" tabindex="-1">主手物品强化状态 <a class="header-anchor" href="#主手物品强化状态" aria-label="Permalink to &quot;主手物品强化状态&quot;">​</a></h2><p>所有占位符读取玩家当前主手持有物品的强化数据。如果主手物品没有强化数据，数值类返回 <code>0</code>，布尔类返回 <code>false</code>，字符串类返回空。</p><table tabindex="0"><thead><tr><th>占位符</th><th>说明</th><th>示例返回值</th></tr></thead><tbody><tr><td><code>%emakistrengthen_mainhand_star%</code></td><td>当前星级</td><td><code>7</code></td></tr><tr><td><code>%emakistrengthen_mainhand_temper%</code></td><td>锻印等级</td><td><code>3</code></td></tr><tr><td><code>%emakistrengthen_mainhand_recipe%</code></td><td>强化配方 ID</td><td><code>weapon_physical</code></td></tr><tr><td><code>%emakistrengthen_mainhand_eligible%</code></td><td>是否可强化</td><td><code>true</code> / <code>false</code></td></tr><tr><td><code>%emakistrengthen_mainhand_success_count%</code></td><td>历史强化成功次数</td><td><code>15</code></td></tr><tr><td><code>%emakistrengthen_mainhand_failure_count%</code></td><td>历史强化失败次数</td><td><code>8</code></td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%emakistrengthen_mainhand_star%             → 7</span></span>
<span class="line"><span>%emakistrengthen_mainhand_temper%           → 3</span></span>
<span class="line"><span>%emakistrengthen_mainhand_recipe%           → weapon_physical</span></span>
<span class="line"><span>%emakistrengthen_mainhand_eligible%         → true</span></span>
<span class="line"><span>%emakistrengthen_mainhand_success_count%    → 15</span></span>
<span class="line"><span>%emakistrengthen_mainhand_failure_count%    → 8</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">使用场景</p><p>这些占位符特别适合在 HUD 插件中显示玩家当前武器的强化等级，或在聊天格式中展示装备星级。</p></div>`,11)])])}const _=a(d,[["render",o]]);export{m as __pageData,_ as default};
